import okhttp3.*
import retrofit2.*
import retrofit2.converter.gson.GsonConverterFactory

// Define a data model to represent User profiles
data class User(val id: Int, val name: String)

interface ApiService {
    @GET("users")
    fun getUsers(): Call<List<User>>
}

class NetworkModule {
    
    companion object{
        private const val BASE_URL = "https://api.example.com/"
        
        fun getRetrofitInstance(authToken: String): Retrofit {
            // Create OkHttp client with authentication interceptor
            val okkHttpClient = OkHttpClient().newBuilder()
                .addInterceptor(Interceptor { chain ->
                    val originalRequest = chain.request()
                    
                    // Add the auth token to request header
                    val newRequest = originalRequest.newBuilder()
                        .header("Authorization", "Bearer $authToken")
                        .build()
                        
                    // Proceed with original request
                    chain.proceed(newRequest)
                })
                .build()
                
            return Retrofit.Builder()
                .baseUrl(BASE_URL)
                .client(okkHttpClient)  // Set OkHttp client to the retrofit instance
                .addConverterFactory(GsonConverterFactory.create())  
                .build()
        }
    }
}